INSERT INTO ingredient_rules (name, aliases, classification, what_it_is, commonly_found_in, one_line_note, countries_restricted, fssai_position, applies_to) VALUES
('Water', ARRAY['Aqua', 'H2O'], 'generally_recognised', 'Universal solvent essential for life and used as a base in most formulations.', 'All beverages, cosmetics, personal care products', 'Primary ingredient in most products', ARRAY[]::TEXT[], 'Permitted without restrictions', 'both'),
('Salt', ARRAY['Sodium Chloride', 'NaCl'], 'generally_recognised', 'Common mineral used for flavoring and preservation.', 'Snacks, processed foods, pickles', 'Essential mineral in moderate amounts', ARRAY[]::TEXT[], 'Permitted as per food standards', 'food'),
('Turmeric', ARRAY['E100', 'Curcumin'], 'generally_recognised', 'Natural yellow colorant and spice derived from turmeric root.', 'Curry powders, mustard, cheese, beverages', 'Natural colorant with traditional use', ARRAY[]::TEXT[], 'Permitted natural color', 'both'),
('Whole Wheat Flour', ARRAY['Atta', 'Wheat Flour'], 'generally_recognised', 'Flour made from grinding whole wheat grains including bran and germ.', 'Bread, chapati, biscuits, baked goods', 'Whole grain flour with fiber', ARRAY[]::TEXT[], 'Permitted without restrictions', 'food'),
('Rice Flour', ARRAY['Ground Rice'], 'generally_recognised', 'Fine powder made from ground rice grains.', 'Gluten-free baking, noodles, snacks', 'Gluten-free alternative flour', ARRAY[]::TEXT[], 'Permitted without restrictions', 'food'),
('Sunflower Oil', ARRAY['Helianthus Annuus Seed Oil'], 'generally_recognised', 'Vegetable oil extracted from sunflower seeds, rich in vitamin E.', 'Cooking oil, salad dressings, cosmetics', 'Common cooking and cosmetic oil', ARRAY[]::TEXT[], 'Permitted edible oil', 'both'),
('Olive Oil', ARRAY['Olea Europaea Fruit Oil'], 'generally_recognised', 'Oil extracted from olives, known for heart-healthy properties.', 'Cooking, salad dressings, skincare', 'Heart-healthy oil with traditional use', ARRAY[]::TEXT[], 'Permitted edible oil', 'both'),
('Glycerin', ARRAY['E422', 'Glycerol'], 'generally_recognised', 'Humectant that attracts moisture, used in food and cosmetics.', 'Baked goods, cosmetics, toothpaste', 'Moisture-retaining ingredient', ARRAY[]::TEXT[], 'Permitted humectant', 'both'),
('Citric Acid', ARRAY['E330'], 'generally_recognised', 'Natural acid found in citrus fruits, used as preservative and flavor enhancer.', 'Beverages, candies, jams, cosmetics', 'Natural preservative and pH adjuster', ARRAY[]::TEXT[], 'Permitted acidulant', 'both'),
('Ascorbic Acid', ARRAY['Vitamin C', 'E300'], 'generally_recognised', 'Vitamin C used as antioxidant and nutrient fortification.', 'Juices, supplements, skincare products', 'Essential vitamin and antioxidant', ARRAY[]::TEXT[], 'Permitted antioxidant and nutrient', 'both'),
('Aloe Vera Extract', ARRAY['Aloe Barbadensis Leaf Extract'], 'generally_recognised', 'Plant extract known for soothing and moisturizing properties.', 'Skincare, haircare, beverages', 'Traditional soothing ingredient', ARRAY[]::TEXT[], 'Permitted natural extract', 'both'),
('Niacinamide', ARRAY['Vitamin B3', 'Nicotinamide'], 'generally_recognised', 'Form of vitamin B3 used for skin health and fortification.', 'Skincare, fortified foods, supplements', 'Essential B vitamin for skin', ARRAY[]::TEXT[], 'Permitted vitamin', 'both'),
('Shea Butter', ARRAY['Butyrospermum Parkii Butter'], 'generally_recognised', 'Natural fat extracted from shea tree nuts, used as moisturizer.', 'Lotions, creams, lip balms', 'Natural moisturizing butter', ARRAY[]::TEXT[], 'Permitted cosmetic ingredient', 'cosmetic'),
('Beeswax', ARRAY['Cera Alba'], 'generally_recognised', 'Natural wax produced by honey bees, used as thickener and emollient.', 'Lip balms, creams, candles', 'Natural wax with emollient properties', ARRAY[]::TEXT[], 'Permitted natural ingredient', 'both'),
('Zinc Oxide', ARRAY['ZnO'], 'generally_recognised', 'Mineral compound used as sunscreen and skin protectant.', 'Sunscreens, diaper creams, cosmetics', 'Physical sunscreen ingredient', ARRAY[]::TEXT[], 'Permitted UV filter', 'cosmetic'),
('Lactic Acid', ARRAY['E270'], 'generally_recognised', 'Alpha hydroxy acid naturally found in milk, used as exfoliant and preservative.', 'Yogurt, pickles, skincare products', 'Natural acid for preservation and exfoliation', ARRAY[]::TEXT[], 'Permitted acidulant', 'both'),
('Tocopherol', ARRAY['Vitamin E', 'E306'], 'generally_recognised', 'Vitamin E used as antioxidant and skin conditioning agent.', 'Oils, cosmetics, supplements', 'Natural antioxidant vitamin', ARRAY[]::TEXT[], 'Permitted antioxidant', 'both'),
('Beta Carotene', ARRAY['E160a', 'Provitamin A'], 'generally_recognised', 'Natural orange pigment and vitamin A precursor.', 'Margarine, cheese, beverages, supplements', 'Natural colorant and vitamin precursor', ARRAY[]::TEXT[], 'Permitted natural color', 'both'),
('Xanthan Gum', ARRAY['E415'], 'generally_recognised', 'Polysaccharide used as thickener and stabilizer.', 'Sauces, dressings, gluten-free baking', 'Common thickening agent', ARRAY[]::TEXT[], 'Permitted stabilizer', 'food'),
('Lecithin', ARRAY['E322', 'Soy Lecithin'], 'generally_recognised', 'Natural emulsifier derived from soybeans or eggs.', 'Chocolate, baked goods, margarine', 'Natural emulsifier', ARRAY[]::TEXT[], 'Permitted emulsifier', 'food');
INSERT INTO ingredient_rules (name, aliases, classification, what_it_is, commonly_found_in, one_line_note, countries_restricted, fssai_position, applies_to) VALUES
('Refined Flour', ARRAY['Maida', 'All-Purpose Flour'], 'worth_knowing', 'Wheat flour with bran and germ removed, lower in fiber than whole wheat.', 'Bread, biscuits, pastries, noodles', 'Processed flour with reduced nutrients', ARRAY[]::TEXT[], 'Permitted but recommended in moderation', 'food'),
('Added Sugar', ARRAY['Sucrose', 'Table Sugar'], 'worth_knowing', 'Refined carbohydrate sweetener added to foods beyond natural sugars.', 'Beverages, sweets, processed foods', 'Excess intake linked to health concerns', ARRAY[]::TEXT[], 'Permitted with labeling requirements', 'food'),
('Palm Oil', ARRAY['Elaeis Guineensis Oil'], 'worth_knowing', 'Vegetable oil high in saturated fat, environmental concerns noted.', 'Biscuits, instant noodles, margarine', 'High saturated fat content', ARRAY[]::TEXT[], 'Permitted edible oil', 'food'),
('MSG', ARRAY['E621', 'Monosodium Glutamate'], 'worth_knowing', 'Flavor enhancer that provides umami taste, debated in research.', 'Instant noodles, chips, Chinese food', 'Flavor enhancer discussed in research', ARRAY[]::TEXT[], 'Permitted with quantity limits', 'food'),
('Sodium Benzoate', ARRAY['E211'], 'worth_knowing', 'Preservative that prevents microbial growth in acidic foods.', 'Soft drinks, pickles, sauces', 'Common preservative with usage limits', ARRAY[]::TEXT[], 'Permitted preservative with ADI limits', 'food'),
('Potassium Sorbate', ARRAY['E202'], 'worth_knowing', 'Preservative effective against molds and yeasts.', 'Cheese, wine, dried fruits', 'Preservative with acceptable daily intake', ARRAY[]::TEXT[], 'Permitted preservative with limits', 'food'),
('Caffeine', ARRAY['Trimethylxanthine'], 'worth_knowing', 'Stimulant naturally found in coffee and tea, added to some products.', 'Coffee, tea, energy drinks, cola', 'Stimulant with recommended daily limits', ARRAY[]::TEXT[], 'Permitted with labeling for high amounts', 'food'),
('Artificial Flavours', ARRAY['Synthetic Flavoring'], 'worth_knowing', 'Chemically synthesized compounds that mimic natural flavors.', 'Candies, beverages, snacks', 'Synthetic flavor compounds', ARRAY[]::TEXT[], 'Permitted flavoring substances', 'food'),
('Sodium Lauryl Sulphate', ARRAY['SLS', 'Sodium Dodecyl Sulfate'], 'worth_knowing', 'Surfactant and foaming agent, can be drying for some skin types.', 'Shampoos, toothpaste, cleansers', 'Common foaming agent', ARRAY[]::TEXT[], 'Permitted surfactant in cosmetics', 'cosmetic'),
('Mineral Oil', ARRAY['Paraffinum Liquidum', 'Petrolatum'], 'worth_knowing', 'Petroleum-derived oil used as moisturizer, occlusive properties.', 'Baby oil, lotions, lip balms', 'Petroleum-derived moisturizer', ARRAY[]::TEXT[], 'Permitted cosmetic ingredient', 'cosmetic'),
('Fragrance', ARRAY['Parfum', 'Perfume'], 'worth_knowing', 'Mixture of aromatic compounds, specific ingredients often undisclosed.', 'Perfumes, cosmetics, personal care', 'Undisclosed mixture of scent compounds', ARRAY[]::TEXT[], 'Permitted with allergen disclosure', 'cosmetic'),
('Alcohol Denat', ARRAY['Denatured Alcohol', 'SD Alcohol'], 'worth_knowing', 'Ethanol made undrinkable, used as solvent and preservative.', 'Perfumes, toners, hairsprays', 'Drying alcohol used as solvent', ARRAY[]::TEXT[], 'Permitted cosmetic ingredient', 'cosmetic'),
('Carrageenan', ARRAY['E407'], 'worth_knowing', 'Seaweed-derived thickener, degraded form discussed in research.', 'Ice cream, plant-based milk, deli meats', 'Seaweed-based thickener', ARRAY[]::TEXT[], 'Permitted stabilizer', 'food'),
('High Fructose Corn Syrup', ARRAY['HFCS', 'Glucose-Fructose Syrup'], 'worth_knowing', 'Sweetener derived from corn, metabolized differently than sucrose.', 'Soft drinks, processed foods', 'Corn-derived sweetener', ARRAY[]::TEXT[], 'Permitted sweetener', 'food'),
('Titanium Dioxide', ARRAY['E171', 'CI 77891'], 'worth_knowing', 'White pigment used as colorant and UV filter.', 'Candies, cosmetics, sunscreens', 'White pigment under review in EU', ARRAY['France (food use)']::TEXT[], 'Permitted with ongoing review', 'both'),
('Sodium', ARRAY['Na', 'Salt Content'], 'worth_knowing', 'Essential mineral, excessive intake linked to blood pressure concerns.', 'Processed foods, snacks, canned goods', 'Essential mineral, excess intake discussed', ARRAY[]::TEXT[], 'Permitted with labeling requirements', 'food'),
('Aspartame', ARRAY['E951'], 'worth_knowing', 'Artificial sweetener, subject to ongoing research and debate.', 'Diet sodas, sugar-free products', 'Artificial sweetener with ADI', ARRAY[]::TEXT[], 'Permitted with ADI and labeling', 'food'),
('Maltodextrin', ARRAY['Modified Starch'], 'worth_knowing', 'Starch-derived carbohydrate used as thickener and filler.', 'Sports drinks, sauces, snacks', 'Rapidly absorbed carbohydrate', ARRAY[]::TEXT[], 'Permitted food additive', 'food'),
('Sodium Nitrate', ARRAY['E251'], 'worth_knowing', 'Preservative used in cured meats, converts to nitrites.', 'Bacon, ham, sausages', 'Curing agent with usage limits', ARRAY[]::TEXT[], 'Permitted with quantity restrictions', 'food'),
('Caramel Colour', ARRAY['E150', 'Caramel Coloring'], 'worth_knowing', 'Brown colorant made from heated sugars, various types exist.', 'Cola, soy sauce, baked goods', 'Heat-processed sugar colorant', ARRAY[]::TEXT[], 'Permitted color with type specifications', 'food');
INSERT INTO ingredient_rules (name, aliases, classification, what_it_is, commonly_found_in, one_line_note, countries_restricted, fssai_position, applies_to) VALUES
('TBHQ', ARRAY['E319', 'Tertiary Butylhydroquinone'], 'commonly_questioned', 'Synthetic antioxidant preservative used to extend shelf life of fats and oils.', 'Instant noodles, crackers, frozen foods', 'Synthetic preservative restricted in some countries', ARRAY['EU (limited)', 'Japan (limited)']::TEXT[], 'Permitted with strict quantity limits', 'food'),
('BHA', ARRAY['E320', 'Butylated Hydroxyanisole'], 'commonly_questioned', 'Synthetic antioxidant preservative, flagged in some research studies.', 'Cereals, chewing gum, potato chips', 'Synthetic antioxidant under research review', ARRAY['Japan (restricted)']::TEXT[], 'Permitted with quantity limits', 'food'),
('BHT', ARRAY['E321', 'Butylated Hydroxytoluene'], 'commonly_questioned', 'Synthetic antioxidant used to prevent rancidity in fats.', 'Cereals, snack foods, cosmetics', 'Synthetic preservative flagged in studies', ARRAY[]::TEXT[], 'Permitted with usage restrictions', 'both'),
('Tartrazine', ARRAY['E102', 'FD&C Yellow 5'], 'commonly_questioned', 'Synthetic yellow dye, linked to hyperactivity concerns in some studies.', 'Candies, soft drinks, chips', 'Synthetic yellow dye with warning labels', ARRAY['Norway', 'Austria']::TEXT[], 'Permitted with labeling requirements', 'food'),
('Sunset Yellow FCF', ARRAY['E110', 'FD&C Yellow 6'], 'commonly_questioned', 'Synthetic orange dye, requires warning labels in some jurisdictions.', 'Orange-colored snacks, beverages', 'Synthetic orange dye flagged in research', ARRAY['Norway', 'Finland']::TEXT[], 'Permitted with labeling', 'food'),
('Carmoisine', ARRAY['E122', 'Azorubine'], 'commonly_questioned', 'Synthetic red dye, banned in some countries due to concerns.', 'Jellies, desserts, beverages', 'Synthetic red dye restricted in some regions', ARRAY['USA', 'Canada', 'Japan']::TEXT[], 'Permitted in India with limits', 'food'),
('Brilliant Blue', ARRAY['E133', 'FD&C Blue 1'], 'commonly_questioned', 'Synthetic blue dye, subject to regulatory limits.', 'Ice cream, candies, beverages', 'Synthetic blue dye with usage limits', ARRAY['Belgium', 'France', 'Germany', 'Switzerland', 'Sweden', 'Austria', 'Norway']::TEXT[], 'Permitted with quantity restrictions', 'food'),
('Acesulfame-K', ARRAY['E950', 'Acesulfame Potassium'], 'commonly_questioned', 'Artificial sweetener, subject to ongoing research.', 'Sugar-free products, diet beverages', 'Artificial sweetener with ADI limits', ARRAY[]::TEXT[], 'Permitted with ADI', 'food'),
('Saccharin', ARRAY['E954'], 'commonly_questioned', 'Oldest artificial sweetener, previously flagged in studies.', 'Tabletop sweeteners, diet products', 'Artificial sweetener with historical concerns', ARRAY['Canada (restricted)']::TEXT[], 'Permitted with ADI', 'food'),
('Trans Fat', ARRAY['PHVO', 'Vanaspati', 'Partially Hydrogenated Vegetable Oil'], 'commonly_questioned', 'Artificially created fat linked to cardiovascular concerns.', 'Margarine, baked goods, fried foods', 'Artificially hardened fat flagged globally', ARRAY['USA (banned)', 'EU (restricted)', 'Canada (banned)']::TEXT[], 'Restricted with phase-out regulations', 'food'),
('Parabens', ARRAY['Methylparaben', 'Propylparaben'], 'commonly_questioned', 'Preservatives used in cosmetics, endocrine disruption discussed.', 'Lotions, shampoos, cosmetics', 'Preservatives with endocrine concerns', ARRAY['Denmark (restricted)']::TEXT[], 'Permitted with concentration limits', 'cosmetic'),
('Formaldehyde Releasers', ARRAY['DMDM Hydantoin', 'Quaternium-15'], 'commonly_questioned', 'Preservatives that slowly release formaldehyde over time.', 'Shampoos, conditioners, body washes', 'Preservatives releasing formaldehyde', ARRAY['EU (restricted)', 'Japan (restricted)']::TEXT[], 'Permitted with limits', 'cosmetic'),
('Mercury Compounds', ARRAY['Thimerosal', 'Mercury Salts'], 'commonly_questioned', 'Heavy metal compounds, neurotoxicity concerns.', 'Skin lightening creams (illegal)', 'Heavy metal restricted globally', ARRAY['USA (banned)', 'EU (banned)', 'Most countries']::TEXT[], 'Banned in cosmetics', 'cosmetic'),
('Hydroquinone', ARRAY['HQ'], 'commonly_questioned', 'Skin lightening agent, banned in cosmetics in many countries.', 'Skin lightening products', 'Skin lightener banned in many regions', ARRAY['EU (banned)', 'Japan (banned)', 'Australia (banned)']::TEXT[], 'Banned in cosmetics in India', 'cosmetic'),
('Phthalates', ARRAY['DBP', 'DEHP', 'Dibutyl Phthalate'], 'commonly_questioned', 'Plasticizers used in cosmetics, endocrine disruption concerns.', 'Nail polish, fragrances, hairsprays', 'Plasticizers with hormone concerns', ARRAY['EU (restricted)', 'California (restricted)']::TEXT[], 'Some types restricted', 'cosmetic'),
('Lead Acetate', ARRAY['Lead Salts'], 'commonly_questioned', 'Heavy metal compound, neurotoxicity and accumulation concerns.', 'Hair dyes (restricted)', 'Heavy metal with toxicity concerns', ARRAY['EU (banned)', 'Canada (banned)']::TEXT[], 'Restricted in cosmetics', 'cosmetic'),
('Triclosan', ARRAY['Triclocarban'], 'commonly_questioned', 'Antimicrobial agent, environmental and resistance concerns.', 'Antibacterial soaps, toothpaste', 'Antimicrobial with resistance concerns', ARRAY['USA (banned in soaps)', 'EU (restricted)']::TEXT[], 'Restricted in personal care', 'cosmetic'),
('Oxybenzone', ARRAY['Benzophenone-3'], 'commonly_questioned', 'Chemical UV filter, endocrine disruption and coral reef concerns.', 'Sunscreens, moisturizers with SPF', 'UV filter with environmental concerns', ARRAY['Hawaii (banned)', 'Palau (banned)']::TEXT[], 'Permitted with concentration limits', 'cosmetic'),
('Potassium Bromate', ARRAY['E924'], 'commonly_questioned', 'Flour treatment agent, flagged as potential carcinogen.', 'Bread, baked goods', 'Flour improver banned in many countries', ARRAY['EU (banned)', 'UK (banned)', 'Canada (banned)', 'China (banned)']::TEXT[], 'Banned in India since 2016', 'food'),
('Allura Red', ARRAY['E129', 'FD&C Red 40'], 'commonly_questioned', 'Synthetic red dye, hyperactivity concerns in some studies.', 'Candies, beverages, desserts', 'Synthetic red dye with warning labels', ARRAY['Denmark', 'Belgium', 'France', 'Germany', 'Switzerland', 'Sweden', 'Austria', 'Norway']::TEXT[], 'Permitted with labeling', 'food');
